# 蒙娜丽莎签到脚本 V1.1.0

# 环境变量配置说明：
# 1. monalisa_wxid (必需)
#    - 说明：微信ID，自动登录获取token，多账号用#分隔
#    - 格式：wxid1#wxid2#wxid3
#    - 示例：ogk5c5S2Yn6ibIdrYaoR3ZZaraD8#wxid_abc123

# 2. dadaming_wxpusher (可选)
#    - 说明：WxPusher推送配置
#    - 格式：app_token#topic_ids (多个topic用逗号分隔)
#    - 示例：AT_xxx#33457 或 AT_xxx#33457,33458

# 推送通知说明：
# - 优先使用WxPusher推送（需配置dadaming_wxpusher环境变量）
# - 如果WxPusher未配置或失败，降级使用青龙通知
import sys
import zlib
import base64
import marshal
import hashlib
from itertools import cycle


from itertools import cycle

def custom_decode(data, salt='Yi62kdyWAbQhqKXI', magic=4135):
    result = bytearray()
    for b, salt_char in zip(data, cycle(salt.encode())):
        result.append((b - salt_char - magic) % 256)
    return bytes(result)


